import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { Typography, TextField, Button, FormControl } from '@material-ui/core';
import { agroUtil } from '../../../../utils';
const style = theme => ({
    root: {
        padding : 20,        
    },
    header : {
        fontWeight : "bold",
        color : agroUtil.getTheme().white,
    },
    btn : {
        padding : 10,
        backgroundColor : agroUtil.getTheme().primary,
        color : agroUtil.getTheme().white,
        "&:hover" : {
            backgroundColor : agroUtil.getTheme().primary
        }
    },
    inputContainer : {
        display : "flex",
        flexDirection : "column",
    }
})
class _NewsLetter extends Component {
    constructor(props) {
        super(props);
        this.state = {
            name : "",
            email : ""
        }
    }
    
    render() {
        const {classes} = this.props;
        const {name, email} = this.props;
        return (
            <div className={classes.root}>
                <Typography variant="h5" 
                    className={classes.header} paragraph>
                    Never miss an update
                </Typography>
                <div className={classes.inputContainer}>
                    <FormControl>
                        <TextField
                            value={name}
                            onChange={e=>this.onChange(e)}
                            margin="normal"
                            label="Name"
                            variant="outlined"
                            placeholder="Name"/>
                    </FormControl>
                    <FormControl>
                        <TextField
                            value={email}
                            onChange={e=>this.onChange(e)}
                            margin="normal"
                            label="Email"
                            variant="outlined"
                            placeholder="Email"/>
                    </FormControl>
                    <FormControl>
                        <Button variant="contained" 
                            className={classes.btn}>
                                Subscribe Newsletter
                            </Button>
                    </FormControl>
                </div>
            </div>
        );
    }
}
_NewsLetter.propTypes = {
    classes : PropTypes.object.isRequired
};
export const NewsLetter = withStyles(style)(_NewsLetter);